  test('Parsing invalid syntax should produce a tree with error nodes.', () async {
    final _config = await createProcessConfigFromJson(json: '{"language":"javascript"}');
    final result = await TreeSitterLanguagePackBridge.process('function function function @@@ %%%', _config);
  });

  test('Loading a nonexistent language should produce an error.', () async {
    await expectLater(() async {
      final _config = await createProcessConfigFromJson(json: '{"language":"nonexistent_xyz"}');
      return TreeSitterLanguagePackBridge.process('', _config);
    }(), throwsA(anything));
  });

  test('Process empty source code succeeds with zero metrics', () async {
    final _config = await createProcessConfigFromJson(json: '{"language":"python"}');
    final result = await TreeSitterLanguagePackBridge.process('', _config);
    expect(result.metrics.totalLines, equals(0));
  });

  test('process() returns error with empty language name', () async {
    await expectLater(() async {
      final _config = await createProcessConfigFromJson(json: '{"language":""}');
      return TreeSitterLanguagePackBridge.process('x = 1', _config);
    }(), throwsA(anything));
  });

  test('process() returns error when config language is unknown', () async {
    await expectLater(() async {
      final _config = await createProcessConfigFromJson(json: '{"language":"nonexistent_xyz"}');
      return TreeSitterLanguagePackBridge.process('x = 1', _config);
    }(), throwsA(anything));
  });

